CREATE VIEW "public"."upcoming_ingredient_demand" AS (WITH upcoming_events AS ( SELECT e.id AS event_id, e.tenant_id, e.event_date, e.guest_count, e.occasion FROM events e WHERE (e.status = ANY (ARRAY['confirmed'::event_status, 'paid'::event_status])) AND e.event_date >= CURRENT_DATE AND e.event_date <= (CURRENT_DATE + '30 days'::interval) ), event_ingredients AS ( SELECT ue.tenant_id AS chef_id, ue.event_id, ue.event_date, ue.occasion, i.id AS ingredient_id, i.name AS ingredient_name, ri.unit, sum(ri.quantity * COALESCE(c.scale_factor, 1::numeric)) AS needed_qty, i.last_price_cents FROM upcoming_events ue JOIN menus m ON m.event_id = ue.event_id JOIN dishes d ON d.menu_id = m.id JOIN components c ON c.dish_id = d.id AND c.recipe_id IS NOT NULL JOIN recipe_ingredients ri ON ri.recipe_id = c.recipe_id JOIN ingredients i ON i.id = ri.ingredient_id WHERE NOT i.is_staple GROUP BY ue.tenant_id, ue.event_id, ue.event_date, ue.occasion, i.id, i.name, ri.unit, i.last_price_cents ) SELECT chef_id, ingredient_id, ingredient_name, unit, sum(needed_qty) AS total_needed_qty, last_price_cents, count(DISTINCT event_id) AS event_count, min(event_date) AS first_event_date, array_agg(DISTINCT occasion) AS events FROM event_ingredients ei GROUP BY chef_id, ingredient_id, ingredient_name, unit, last_price_cents);--> statement-breakpoint
CREATE VIEW "public"."inventory_expiry_alerts" AS (SELECT ib.chef_id, ib.id AS batch_id, ib.ingredient_id, ib.ingredient_name, ib.expiry_date, ib.remaining_qty, ib.unit, ib.unit_cost_cents, (ib.remaining_qty * COALESCE(ib.unit_cost_cents, 0)::numeric)::integer AS at_risk_cost_cents, sl.name AS location_name, CASE WHEN ib.expiry_date <= CURRENT_DATE THEN 'expired'::text WHEN ib.expiry_date <= (CURRENT_DATE + 3) THEN 'critical'::text WHEN ib.expiry_date <= (CURRENT_DATE + 7) THEN 'warning'::text ELSE 'ok'::text END AS urgency FROM inventory_batches ib LEFT JOIN storage_locations sl ON sl.id = ib.location_id WHERE NOT ib.is_depleted AND ib.expiry_date IS NOT NULL AND ib.expiry_date <= (CURRENT_DATE + '7 days'::interval));--> statement-breakpoint
CREATE VIEW "public"."event_inventory_variance" AS (WITH expected_usage AS ( SELECT e.id AS event_id, e.tenant_id AS chef_id, i.id AS ingredient_id, i.name AS ingredient_name, ri.unit, sum(ri.quantity * COALESCE(c.scale_factor, 1::numeric)) AS expected_qty, i.last_price_cents FROM events e JOIN menus m ON m.event_id = e.id JOIN dishes d ON d.menu_id = m.id JOIN components c ON c.dish_id = d.id AND c.recipe_id IS NOT NULL JOIN recipe_ingredients ri ON ri.recipe_id = c.recipe_id JOIN ingredients i ON i.id = ri.ingredient_id WHERE e.status = ANY (ARRAY['completed'::event_status, 'in_progress'::event_status]) GROUP BY e.id, e.tenant_id, i.id, i.name, ri.unit, i.last_price_cents ), actual_usage AS ( SELECT it.event_id, it.chef_id, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, abs(sum(it.quantity)) AS actual_qty FROM inventory_transactions it WHERE it.event_id IS NOT NULL AND it.transaction_type = 'event_deduction'::inventory_transaction_type GROUP BY it.event_id, it.chef_id, it.ingredient_id, it.unit ) SELECT eu.event_id, eu.chef_id, eu.ingredient_id, eu.ingredient_name, eu.unit, eu.expected_qty, COALESCE(au.actual_qty, 0::numeric) AS actual_qty, COALESCE(au.actual_qty, 0::numeric) - eu.expected_qty AS variance_qty, eu.last_price_cents, ((COALESCE(au.actual_qty, 0::numeric) - eu.expected_qty) * COALESCE(eu.last_price_cents, 0)::numeric)::integer AS variance_cost_cents FROM expected_usage eu LEFT JOIN actual_usage au ON eu.event_id = au.event_id AND eu.ingredient_id = au.ingredient_id);--> statement-breakpoint
CREATE VIEW "public"."event_financial_summary" AS (SELECT e.id AS event_id, e.tenant_id, e.quoted_price_cents, e.payment_status, COALESCE(sum(le.amount_cents) FILTER (WHERE le.is_refund = false), 0::bigint) AS total_paid_cents, COALESCE(sum(abs(le.amount_cents)) FILTER (WHERE le.is_refund = true), 0::bigint) AS total_refunded_cents, COALESCE(sum(le.amount_cents), 0::bigint) AS net_revenue_cents, COALESCE(sum(ex.amount_cents), 0::bigint) AS total_expenses_cents, e.tip_amount_cents, COALESCE(sum(le.amount_cents), 0::bigint) - COALESCE(sum(ex.amount_cents), 0::bigint) AS profit_cents, CASE WHEN COALESCE(sum(le.amount_cents), 0::bigint) > 0 THEN (COALESCE(sum(le.amount_cents), 0::bigint) - COALESCE(sum(ex.amount_cents), 0::bigint))::numeric / COALESCE(sum(le.amount_cents), 1::bigint)::numeric ELSE 0::numeric END AS profit_margin, CASE WHEN COALESCE(sum(le.amount_cents), 0::bigint) > 0 THEN COALESCE(sum(ex.amount_cents), 0::bigint)::numeric / COALESCE(sum(le.amount_cents), 1::bigint)::numeric ELSE 0::numeric END AS food_cost_percentage, e.quoted_price_cents - COALESCE(sum(le.amount_cents) FILTER (WHERE le.is_refund = false), 0::bigint) AS outstanding_balance_cents FROM events e LEFT JOIN ledger_entries le ON le.event_id = e.id LEFT JOIN expenses ex ON ex.event_id = e.id GROUP BY e.id);--> statement-breakpoint
CREATE VIEW "public"."event_time_summary" AS (SELECT id AS event_id, tenant_id, EXTRACT(epoch FROM shopping_completed_at - shopping_started_at) / 60::numeric AS shopping_duration_minutes, EXTRACT(epoch FROM prep_completed_at - prep_started_at) / 60::numeric AS prep_duration_minutes, EXTRACT(epoch FROM travel_completed_at - travel_started_at) / 60::numeric AS travel_duration_minutes, EXTRACT(epoch FROM service_completed_at - service_started_at) / 60::numeric AS service_duration_minutes, EXTRACT(epoch FROM reset_completed_at - reset_started_at) / 60::numeric AS reset_duration_minutes, (COALESCE(EXTRACT(epoch FROM shopping_completed_at - shopping_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM prep_completed_at - prep_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM travel_completed_at - travel_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM service_completed_at - service_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM reset_completed_at - reset_started_at), 0::numeric)) / 60::numeric AS total_time_minutes, (COALESCE(EXTRACT(epoch FROM shopping_completed_at - shopping_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM prep_completed_at - prep_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM travel_completed_at - travel_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM service_completed_at - service_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM reset_completed_at - reset_started_at), 0::numeric)) / 3600::numeric AS total_time_hours FROM events);--> statement-breakpoint
CREATE VIEW "public"."client_financial_summary" AS (SELECT c.id AS client_id, c.tenant_id, c.lifetime_value_cents, c.total_events_count, count(e.id) FILTER (WHERE e.status = 'completed'::event_status) AS total_events_completed, count(e.id) FILTER (WHERE e.status = 'cancelled'::event_status) AS total_events_cancelled, CASE WHEN count(e.id) FILTER (WHERE e.status = 'completed'::event_status) > 0 THEN c.lifetime_value_cents / count(e.id) FILTER (WHERE e.status = 'completed'::event_status) ELSE 0::bigint END AS average_spend_per_event, COALESCE(sum(le.amount_cents) FILTER (WHERE le.entry_type = 'tip'::ledger_entry_type), 0::bigint) AS total_tips_given_cents, CASE WHEN c.lifetime_value_cents > 0 THEN COALESCE(sum(le.amount_cents) FILTER (WHERE le.entry_type = 'tip'::ledger_entry_type), 0::bigint)::numeric / c.lifetime_value_cents::numeric ELSE 0::numeric END AS average_tip_percentage, COALESCE(sum(e.quoted_price_cents) FILTER (WHERE e.payment_status <> 'paid'::payment_status), 0::bigint) AS outstanding_balance_cents, c.last_event_date, c.first_event_date, CURRENT_DATE - c.last_event_date AS days_since_last_event, (CURRENT_DATE - c.last_event_date) > 180 AS is_dormant FROM clients c LEFT JOIN events e ON e.client_id = c.id LEFT JOIN ledger_entries le ON le.client_id = c.id GROUP BY c.id);--> statement-breakpoint
CREATE VIEW "public"."menu_cost_summary" AS (SELECT m.id AS menu_id, m.tenant_id, m.event_id, m.name AS menu_name, get_menu_total_component_count(m.id) AS total_component_count, compute_menu_cost_cents(m.id) AS total_recipe_cost_cents, CASE WHEN e.guest_count > 0 THEN compute_menu_cost_cents(m.id) / e.guest_count ELSE NULL::integer END AS cost_per_guest_cents, CASE WHEN e.quoted_price_cents > 0 THEN (compute_menu_cost_cents(m.id)::numeric / e.quoted_price_cents::numeric * 100::numeric)::numeric(5,2) ELSE NULL::numeric END AS food_cost_percentage, ( SELECT count(*) = count(c.recipe_id) FROM components c JOIN dishes d ON d.id = c.dish_id WHERE d.menu_id = m.id) AS has_all_recipe_costs FROM menus m LEFT JOIN events e ON e.id = m.event_id);--> statement-breakpoint
CREATE VIEW "public"."dish_component_summary" AS (SELECT id AS dish_id, tenant_id, menu_id, course_number, course_name, get_dish_component_count(id) AS component_count, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.is_make_ahead = true) AS make_ahead_count, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.recipe_id IS NOT NULL) AS components_with_recipes, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.recipe_id IS NULL) AS components_without_recipes FROM dishes d);--> statement-breakpoint
CREATE VIEW "public"."ingredient_usage_summary" AS (SELECT id AS ingredient_id, tenant_id, name AS ingredient_name, category, ( SELECT count(*) AS count FROM recipe_ingredients WHERE recipe_ingredients.ingredient_id = i.id) AS times_used, ( SELECT array_agg(DISTINCT r.name) AS array_agg FROM recipe_ingredients ri JOIN recipes r ON r.id = ri.recipe_id WHERE ri.ingredient_id = i.id) AS recipes_using, ( SELECT max(r.last_cooked_at) AS max FROM recipe_ingredients ri JOIN recipes r ON r.id = ri.recipe_id WHERE ri.ingredient_id = i.id) AS last_used_in_recipe_at FROM ingredients i WHERE archived = false);--> statement-breakpoint
CREATE VIEW "public"."unified_inbox" AS (SELECT c.id, c.tenant_id, 'chat'::text AS source, c.last_message_preview AS preview, COALESCE(c.last_message_at, c.created_at) AS activity_at, c.last_message_sender_id AS actor_id, NULL::uuid AS conversation_id, c.inquiry_id, c.event_id, NULL::uuid AS client_id, c.context_type::text AS content_type, false AS is_read FROM conversations c WHERE c.last_message_at IS NOT NULL UNION ALL SELECT m.id, m.tenant_id, 'message'::text AS source, CASE WHEN m.subject IS NOT NULL AND m.subject <> ''::text THEN (m.subject || ': '::text) || "left"(m.body, 150) ELSE "left"(m.body, 200) END AS preview, COALESCE(m.sent_at, m.created_at) AS activity_at, m.from_user_id AS actor_id, NULL::uuid AS conversation_id, m.inquiry_id, m.event_id, m.client_id, m.channel::text AS content_type, false AS is_read FROM messages m WHERE m.status = ANY (ARRAY['sent'::message_status, 'logged'::message_status]) UNION ALL SELECT ws.id, ws.tenant_id, 'wix'::text AS source, CASE WHEN ws.submitter_name IS NOT NULL THEN ws.submitter_name || ' submitted a form'::text WHEN ws.submitter_email IS NOT NULL THEN ws.submitter_email || ' submitted a form'::text ELSE 'New Wix form submission'::text END AS preview, ws.created_at AS activity_at, NULL::uuid AS actor_id, NULL::uuid AS conversation_id, ws.inquiry_id, NULL::uuid AS event_id, ws.client_id, 'wix_form'::text AS content_type, ws.status = 'completed'::text AS is_read FROM wix_submissions ws UNION ALL SELECT n.id, n.tenant_id, 'notification'::text AS source, COALESCE(n.body, n.title) AS preview, n.created_at AS activity_at, NULL::uuid AS actor_id, NULL::uuid AS conversation_id, n.inquiry_id, n.event_id, n.client_id, n.action AS content_type, n.read_at IS NOT NULL AS is_read FROM notifications n WHERE n.archived_at IS NULL);--> statement-breakpoint
CREATE VIEW "public"."dish_index_summary" AS (SELECT di.id, di.tenant_id, di.name, di.course, di.description, di.dietary_tags, di.allergen_flags, di.times_served, di.first_served, di.last_served, di.is_signature, di.rotation_status, di.linked_recipe_id, di.prep_complexity, di.plating_difficulty, di.tags, di.season_affinity, di.archived, r.name AS recipe_name, rcs.total_ingredient_cost_cents AS recipe_cost_cents, rcs.cost_per_portion_cents AS per_portion_cost_cents, COALESCE(fb.avg_rating, 0::numeric) AS avg_rating, COALESCE(fb.feedback_count, 0::bigint) AS feedback_count FROM dish_index di LEFT JOIN recipes r ON r.id = di.linked_recipe_id LEFT JOIN recipe_cost_summary rcs ON rcs.recipe_id = di.linked_recipe_id LEFT JOIN ( SELECT dish_feedback.dish_id, avg(dish_feedback.rating)::numeric(3,1) AS avg_rating, count(*) AS feedback_count FROM dish_feedback GROUP BY dish_feedback.dish_id) fb ON fb.dish_id = di.id);--> statement-breakpoint
CREATE VIEW "public"."communication_inbox_items" AS (WITH latest_event AS ( SELECT DISTINCT ON (ce.thread_id) ce.id AS communication_event_id, ce.tenant_id, ce.thread_id, ce."timestamp", ce.sender_identity, ce.source, ce.direction, ce.raw_content, ce.normalized_content, ce.status AS communication_status, ce.linked_entity_type, ce.linked_entity_id, ce.resolved_client_id FROM communication_events ce ORDER BY ce.thread_id, ce."timestamp" DESC, ce.created_at DESC ), overdue_timer AS ( SELECT fut.thread_id, min(fut.due_at) AS next_due_at, bool_or(fut.status = 'active'::follow_up_timer_status AND fut.due_at <= now()) AS has_overdue FROM follow_up_timers fut GROUP BY fut.thread_id ), pending_links AS ( SELECT sl.communication_event_id, count(*) FILTER (WHERE sl.status = 'pending'::suggested_link_status) AS pending_link_count, max(sl.confidence_score) FILTER (WHERE sl.status = 'pending'::suggested_link_status) AS top_pending_confidence FROM suggested_links sl GROUP BY sl.communication_event_id ) SELECT ct.id AS thread_id, ct.tenant_id, ct.client_id, ct.last_activity_at, ct.state AS thread_state, ct.snoozed_until, le.communication_event_id, le."timestamp" AS event_timestamp, le.sender_identity, le.source, le.direction, le.raw_content, le.normalized_content, le.communication_status, le.linked_entity_type, le.linked_entity_id, le.resolved_client_id, COALESCE(ot.next_due_at, NULL::timestamp with time zone) AS next_follow_up_due_at, COALESCE(ot.has_overdue, false) AS has_overdue_follow_up, COALESCE(pl.pending_link_count, 0::bigint) AS pending_link_count, COALESCE(pl.top_pending_confidence, 0::numeric) AS top_pending_confidence, CASE WHEN ct.state = 'snoozed'::conversation_thread_state AND (ct.snoozed_until IS NULL OR ct.snoozed_until > now()) THEN 'snoozed'::text WHEN le.communication_status = 'resolved'::communication_event_status OR ct.state = 'closed'::conversation_thread_state THEN 'resolved'::text WHEN le.communication_status = 'unlinked'::communication_event_status THEN 'unlinked'::text ELSE 'needs_attention'::text END AS tab, COALESCE(ot.has_overdue, false) = true AND ct.state = 'active'::conversation_thread_state OR le.communication_status = 'unlinked'::communication_event_status AND ct.state = 'active'::conversation_thread_state OR COALESCE(pl.pending_link_count, 0::bigint) > 0 AND ct.state = 'active'::conversation_thread_state AS needs_attention, ct.is_starred FROM conversation_threads ct JOIN latest_event le ON le.thread_id = ct.id LEFT JOIN overdue_timer ot ON ot.thread_id = ct.id LEFT JOIN pending_links pl ON pl.communication_event_id = le.communication_event_id);--> statement-breakpoint
CREATE VIEW "public"."sale_financial_summary" AS (SELECT s.id AS sale_id, s.tenant_id, s.sale_number, s.status, s.channel, s.total_cents, s.tax_cents, s.tip_cents, s.discount_cents, s.subtotal_cents, COALESCE(pay.total_paid_cents, 0::bigint) AS total_paid_cents, COALESCE(pay.total_tips_cents, 0::bigint) AS total_tips_cents, COALESCE(ref.total_refunded_cents, 0::bigint) AS total_refunded_cents, s.total_cents - COALESCE(pay.total_paid_cents, 0::bigint) + COALESCE(ref.total_refunded_cents, 0::bigint) AS balance_due_cents, COALESCE(cost.total_cost_cents, 0::bigint) AS total_cost_cents, s.total_cents - COALESCE(cost.total_cost_cents, 0::bigint) AS gross_profit_cents, s.created_at, s.event_id, s.client_id FROM sales s LEFT JOIN LATERAL ( SELECT sum(commerce_payments.amount_cents) FILTER (WHERE commerce_payments.status = ANY (ARRAY['captured'::commerce_payment_status, 'settled'::commerce_payment_status])) AS total_paid_cents, sum(commerce_payments.tip_cents) FILTER (WHERE commerce_payments.status = ANY (ARRAY['captured'::commerce_payment_status, 'settled'::commerce_payment_status])) AS total_tips_cents FROM commerce_payments WHERE commerce_payments.sale_id = s.id) pay ON true LEFT JOIN LATERAL ( SELECT sum(commerce_refunds.amount_cents) FILTER (WHERE commerce_refunds.status = 'processed'::refund_status) AS total_refunded_cents FROM commerce_refunds WHERE commerce_refunds.sale_id = s.id) ref ON true LEFT JOIN LATERAL ( SELECT sum(sale_items.unit_cost_cents * sale_items.quantity) AS total_cost_cents FROM sale_items WHERE sale_items.sale_id = s.id AND sale_items.unit_cost_cents IS NOT NULL) cost ON true);--> statement-breakpoint
CREATE VIEW "public"."event_rsvp_summary" AS (SELECT event_id, tenant_id, count(*)::integer AS total_guests, count(*) FILTER (WHERE rsvp_status = 'attending'::rsvp_status)::integer AS attending_count, count(*) FILTER (WHERE rsvp_status = 'declined'::rsvp_status)::integer AS declined_count, count(*) FILTER (WHERE rsvp_status = 'maybe'::rsvp_status)::integer AS maybe_count, count(*) FILTER (WHERE rsvp_status = 'pending'::rsvp_status AND COALESCE(attendance_queue_status, 'none'::text) <> 'waitlisted'::text)::integer AS pending_count, count(*) FILTER (WHERE COALESCE(attendance_queue_status, 'none'::text) = 'waitlisted'::text)::integer AS waitlisted_count, count(*) FILTER (WHERE plus_one = true)::integer AS plus_one_count, ARRAY( SELECT DISTINCT unnest(eg2.dietary_restrictions) AS unnest FROM event_guests eg2 WHERE eg2.event_id = eg.event_id AND (eg2.rsvp_status = ANY (ARRAY['attending'::rsvp_status, 'maybe'::rsvp_status])) AND eg2.dietary_restrictions <> '{}'::text[]) AS all_dietary_restrictions, ARRAY( SELECT DISTINCT unnest(eg2.allergies) AS unnest FROM event_guests eg2 WHERE eg2.event_id = eg.event_id AND (eg2.rsvp_status = ANY (ARRAY['attending'::rsvp_status, 'maybe'::rsvp_status])) AND eg2.allergies <> '{}'::text[]) AS all_allergies FROM event_guests eg GROUP BY event_id, tenant_id);--> statement-breakpoint
CREATE VIEW "public"."inventory_current_stock" AS (SELECT it.chef_id, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, sum(it.quantity) AS current_qty, ic.par_level, ic.vendor_id, max(it.created_at) AS last_movement_at, count(*) AS transaction_count FROM inventory_transactions it LEFT JOIN inventory_counts ic ON ic.chef_id = it.chef_id AND ic.ingredient_id = it.ingredient_id GROUP BY it.chef_id, it.ingredient_id, it.unit, ic.par_level, ic.vendor_id);--> statement-breakpoint
CREATE VIEW "public"."inventory_by_location" AS (SELECT it.chef_id, it.location_id, sl.name AS location_name, sl.location_type, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, sum(it.quantity) AS current_qty FROM inventory_transactions it LEFT JOIN storage_locations sl ON sl.id = it.location_id WHERE it.location_id IS NOT NULL GROUP BY it.chef_id, it.location_id, sl.name, sl.location_type, it.ingredient_id, it.unit HAVING sum(it.quantity) <> 0::numeric);--> statement-breakpoint
CREATE VIEW "public"."guest_feedback_summary" AS (SELECT event_id, tenant_id, count(*) FILTER (WHERE submitted_at IS NOT NULL)::integer AS submitted_count, count(*) FILTER (WHERE submitted_at IS NULL AND sent_at IS NOT NULL)::integer AS pending_count, count(*)::integer AS total_sent, round(avg(overall_rating) FILTER (WHERE submitted_at IS NOT NULL), 2) AS avg_overall, round(avg(food_rating) FILTER (WHERE submitted_at IS NOT NULL), 2) AS avg_food, round(avg(experience_rating) FILTER (WHERE submitted_at IS NOT NULL), 2) AS avg_experience, count(*) FILTER (WHERE testimonial_consent = true)::integer AS testimonial_count FROM guest_feedback gf GROUP BY event_id, tenant_id);--> statement-breakpoint
CREATE VIEW "public"."recipe_cost_summary" AS (SELECT id AS recipe_id, tenant_id, name AS recipe_name, category, COALESCE(total_cost_cents, compute_recipe_cost_cents(id)) AS total_ingredient_cost_cents, COALESCE(cost_per_serving_cents, CASE WHEN yield_quantity > 0::numeric THEN (compute_recipe_cost_cents(id)::numeric / yield_quantity)::integer ELSE NULL::integer END) AS cost_per_portion_cents, ( SELECT count(*) AS count FROM recipe_ingredients WHERE recipe_ingredients.recipe_id = r.id) AS ingredient_count, ( SELECT count(*) = count(COALESCE(i.cost_per_unit_cents, i.last_price_cents)) FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id) AS has_all_prices, ( SELECT max(i.last_price_date) AS max FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id) AS last_price_updated_at, ( SELECT count(*) AS count FROM recipe_sub_recipes WHERE recipe_sub_recipes.parent_recipe_id = r.id) AS sub_recipe_count FROM recipes r WHERE archived = false);--> statement-breakpoint
CREATE VIEW "public"."ingredient_monthly_price_avg" AS (SELECT tenant_id, ingredient_id, EXTRACT(year FROM purchase_date)::integer AS year, EXTRACT(month FROM purchase_date)::integer AS month, round(avg(price_cents))::integer AS avg_price_cents, min(price_cents) AS min_price_cents, max(price_cents) AS max_price_cents, count(*) AS data_points FROM ingredient_price_history GROUP BY tenant_id, ingredient_id, (EXTRACT(year FROM purchase_date)), (EXTRACT(month FROM purchase_date)));--> statement-breakpoint
CREATE VIEW "public"."ingredient_best_vendor_price" AS (SELECT DISTINCT ON (chef_id, ingredient_name) chef_id, ingredient_name, ingredient_id, vendor_id, unit_price_cents, price_unit, lead_time_days, min_order_qty, min_order_unit, is_preferred FROM vendor_preferred_ingredients WHERE unit_price_cents IS NOT NULL ORDER BY chef_id, ingredient_name, unit_price_cents);--> statement-breakpoint
